<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';$pdo=obtenerConexion();$docenteId=docenteSupervisadoAtenea($pdo);$curso=docenteId($_GET['curso']??0);if($curso)exigirCursoDocente($pdo,$docenteId,$curso);docenteCabecera('Comunicación','comunicaciones','Mensajes únicamente a estudiantes de cursos asignados.');docenteSelectorSupervision($pdo);$cursos=cursosDocenteAtenea($pdo,$docenteId);$estudiantes=[];if($curso){$q=$pdo->prepare("SELECT u.id,u.nombre,u.apellido,u.correo FROM estudiantes_docentes ed JOIN usuarios u ON u.id=ed.estudiante_id WHERE ed.docente_id=:d AND ed.asignatura_id=:a AND ed.estado='activo' AND u.estado='activo' AND u.deleted_at IS NULL ORDER BY u.nombre,u.apellido LIMIT 200");$q->execute(['d'=>$docenteId,'a'=>$curso]);$estudiantes=$q->fetchAll();}$q=$pdo->prepare('SELECT h.*,a.nombre asignatura,u.nombre,u.apellido FROM comunicacion_hilos h LEFT JOIN asignaturas a ON a.id=h.asignatura_id LEFT JOIN usuarios u ON u.id=h.usuario_id WHERE h.docente_id=:d ORDER BY h.ultimo_mensaje_at DESC LIMIT 100');$q->execute(['d'=>$docenteId]);$hilos=$q->fetchAll();?>
<?php if($docenteId&&$cursos):?><div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Nuevo mensaje</h2><form method="get" class="row g-2 mb-3"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><div class="col-md-8"><select class="form-select" name="curso" required><option value="">Selecciona un curso</option><?php foreach($cursos as$c):?><option value="<?=$c['id']?>" <?=$curso===$c['id']?'selected':''?>><?=atenea_e($c['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-4"><button class="btn btn-outline-primary w-100">Cargar estudiantes</button></div></form><?php if($curso):?><form method="post" action="comunicacion_enviar.php" class="row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><input type="hidden" name="asignatura_id" value="<?=$curso?>"><div class="col-md-6"><label class="form-label">Estudiante del curso</label><select class="form-select" name="estudiante_id" required><option value="">Selecciona</option><?php foreach($estudiantes as$e):?><option value="<?=$e['id']?>"><?=atenea_e(trim($e['nombre'].' '.$e['apellido']).' · '.$e['correo'])?></option><?php endforeach;?></select></div><div class="col-md-6"><label class="form-label">Asunto</label><input class="form-control" name="asunto" maxlength="190" required></div><div class="col-12"><label class="form-label">Mensaje</label><textarea class="form-control" name="mensaje" maxlength="10000" rows="5" required></textarea></div><div class="col-12"><button class="btn btn-primary">Guardar y enviar por correo</button></div></form><?php if(!$estudiantes):?><p class="text-muted mt-3">Este curso no tiene estudiantes activos.</p><?php endif;?><?php endif;?></div></div><?php endif;?><div class="card card-rounded"><div class="card-body"><h2 class="h5">Historial académico</h2><div class="table-responsive"><table class="table"><thead><tr><th>Asunto</th><th>Estudiante</th><th>Curso</th><th>Estado</th><th>Fecha</th></tr></thead><tbody><?php foreach($hilos as$h):?><tr><td><?=atenea_e($h['asunto'])?></td><td><?=atenea_e(trim($h['nombre'].' '.$h['apellido']))?></td><td><?=atenea_e((string)$h['asignatura'])?></td><td><?=atenea_e($h['estado'])?></td><td><?=date('d/m/Y H:i',strtotime($h['ultimo_mensaje_at']))?></td></tr><?php endforeach;?><?php if(!$hilos):?><tr><td colspan="5" class="text-center py-5">No hay comunicaciones académicas.</td></tr><?php endif;?></tbody></table></div></div></div><?php docentePie();
